import React, { useState, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import { getProducts } from '../utils/api';
import ProductCard from '../components/ProductCard';
import './ProductList.css';

const CATEGORIES = ['Mobiles', 'Electronics', 'Fashion', 'Home', 'Appliances', 'Books', 'Sports', 'Beauty', 'Toys', 'Grocery'];
const SORT_OPTIONS = [
  { label: 'Relevance', value: '' },
  { label: 'Price: Low to High', value: 'price-asc' },
  { label: 'Price: High to Low', value: 'price-desc' },
  { label: 'Rating', value: 'rating' },
  { label: 'Popularity', value: 'popular' },
];

export default function ProductList() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [products, setProducts] = useState([]);
  const [total, setTotal] = useState(0);
  const [pages, setPages] = useState(1);
  const [loading, setLoading] = useState(true);

  const category = searchParams.get('category') || '';
  const search = searchParams.get('search') || '';
  const sort = searchParams.get('sort') || '';
  const page = parseInt(searchParams.get('page') || '1');
  const minPrice = searchParams.get('minPrice') || '';
  const maxPrice = searchParams.get('maxPrice') || '';
  const rating = searchParams.get('rating') || '';
  const featured = searchParams.get('featured') || '';

  const fetchProducts = useCallback(() => {
    setLoading(true);
    const params = { page, limit: 12 };
    if (category) params.category = category;
    if (search) params.search = search;
    if (sort) params.sort = sort;
    if (minPrice) params.minPrice = minPrice;
    if (maxPrice) params.maxPrice = maxPrice;
    if (rating) params.rating = rating;
    if (featured) params.featured = featured;

    getProducts(params)
      .then(res => { setProducts(res.data.products); setTotal(res.data.total); setPages(res.data.pages); })
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, [category, search, sort, page, minPrice, maxPrice, rating, featured]);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  const update = (key, value) => {
    const p = new URLSearchParams(searchParams);
    if (value) p.set(key, value); else p.delete(key);
    p.delete('page');
    setSearchParams(p);
  };

  return (
    <div className="product-list-page">
      <div className="container product-list-layout">
        {/* Sidebar Filters */}
        <aside className="filters-sidebar">
          <h3>Filters</h3>

          <div className="filter-group">
            <h4>Category</h4>
            {CATEGORIES.map(cat => (
              <label key={cat} className="filter-option">
                <input type="radio" name="category" checked={category === cat} onChange={() => update('category', cat)} />
                {cat}
              </label>
            ))}
            {category && <button className="clear-filter" onClick={() => update('category', '')}>Clear</button>}
          </div>

          <div className="filter-group">
            <h4>Price Range</h4>
            <div className="price-inputs">
              <input className="form-control" placeholder="Min ₹" value={minPrice} onChange={e => update('minPrice', e.target.value)} type="number" />
              <span>-</span>
              <input className="form-control" placeholder="Max ₹" value={maxPrice} onChange={e => update('maxPrice', e.target.value)} type="number" />
            </div>
          </div>

          <div className="filter-group">
            <h4>Customer Rating</h4>
            {[4, 3, 2].map(r => (
              <label key={r} className="filter-option">
                <input type="radio" name="rating" checked={rating === String(r)} onChange={() => update('rating', r)} />
                {'★'.repeat(r)} & above
              </label>
            ))}
            {rating && <button className="clear-filter" onClick={() => update('rating', '')}>Clear</button>}
          </div>
        </aside>

        {/* Products */}
        <div className="products-main">
          <div className="products-header">
            <div>
              <h2>{search ? `Results for "${search}"` : category || 'All Products'}</h2>
              <p className="results-count">{total.toLocaleString()} results</p>
            </div>
            <select className="form-control sort-select" value={sort} onChange={e => update('sort', e.target.value)}>
              {SORT_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
            </select>
          </div>

          {loading ? (
            <div className="loading-screen"><div className="spinner"></div></div>
          ) : products.length === 0 ? (
            <div className="empty-state">
              <div style={{fontSize:'60px'}}>🔍</div>
              <h3>No products found</h3>
              <p>Try adjusting your filters or search term</p>
            </div>
          ) : (
            <>
              <div className="products-grid">{products.map(p => <ProductCard key={p._id} product={p} />)}</div>

              {pages > 1 && (
                <div className="pagination">
                  {Array.from({ length: pages }, (_, i) => i + 1).map(p => (
                    <button
                      key={p}
                      className={`page-btn ${page === p ? 'active' : ''}`}
                      onClick={() => { const np = new URLSearchParams(searchParams); np.set('page', p); setSearchParams(np); }}
                    >{p}</button>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
